import time, math, uuid

class RiskManager:
    def __init__(self, max_notional_usdt, max_daily_loss_usdt):
        self.max_notional = float(max_notional_usdt)
        self.max_daily_loss = float(max_daily_loss_usdt)
        self.day_start = time.strftime("%Y-%m-%d")
        self.realized_pnl = 0.0
        self.tripped = False

    def new_day_if_needed(self):
        d = time.strftime("%Y-%m-%d")
        if d != self.day_start:
            self.day_start, self.realized_pnl, self.tripped = d, 0.0, False

    def on_fill(self, realized_pnl_delta):
        self.new_day_if_needed()
        self.realized_pnl += float(realized_pnl_delta)
        if self.realized_pnl <= -self.max_daily_loss:
            self.tripped = True

    def can_enter(self, price, qty, leverage=3):
        self.new_day_if_needed()
        if self.tripped: return False
        notional = abs(price * qty) * leverage
        return notional <= self.max_notional

def cid(tag=""):
    return f"{tag}{int(time.time()*1000)}-{uuid.uuid4().hex[:6]}"
```

ccxt setup and safe execution sketch:

```
import ccxt

exchange = ccxt.binanceusdm({'apiKey': API_KEY, 'secret': API_SECRET, 'enableRateLimit': True})
exchange.options = {'defaultType': 'future'}

symbol = 'BTC/USDT'
leverage = 3
try:
    exchange.setLeverage(leverage, symbol)
    # ensure one-way mode
    if hasattr(exchange, 'setPositionMode'):
        exchange.setPositionMode(False)  # False = one-way on Binance
except Exception as e:
    print("leverage/positionMode setup:", e)

rm = RiskManager(max_notional_usdt=5000, max_daily_loss_usdt=200)  # start small, adjust later

def get_pos_amt(sym):
    pos = [p for p in exchange.fetchPositions([sym]) if p['symbol'] == sym]
    if pos:
        return float(pos[0].get('contracts') or pos[0].get('positionAmt') or 0.0)
    return 0.0

def exit_to_flat(sym, pos_amt):
    if pos_amt == 0: return None
    side = 'sell' if pos_amt > 0 else 'buy'
    params = {'reduceOnly': True, 'newClientOrderId': cid('exit-')}
    return exchange.create_order(sym, 'market', side, abs(pos_amt), None, params)

def enter_bias(sym, target_bias, unit_qty, last_price):
    if target_bias == 0: return None
    if not rm.can_enter(last_price, unit_qty, leverage): return None
    side = 'buy' if target_bias > 0 else 'sell'
    params = {'newClientOrderId': cid('enter-')}
    return exchange.create_order(sym, 'market', side, unit_qty, None, params)
```

